import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.internal.bind.DateTypeAdapter;
import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

public class DateTypeAdapterTest {

    private DateTypeAdapter dateTypeAdapter;

    @BeforeEach
    public void setUp() {
        dateTypeAdapter = new DateTypeAdapter();
    }

    @Test
    public void testRead_NullToken_ReturnsNull() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        // nextNull() should be called
        doNothing().when(jsonReader).nextNull();

        Date result = dateTypeAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    public void testRead_ValidDateToken_ReturnsDate() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        // Use reflection to invoke private deserializeToDate method
        Method method = DateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        method.setAccessible(true);

        // Spy on dateTypeAdapter to mock deserializeToDate
        DateTypeAdapter spyAdapter = Mockito.spy(dateTypeAdapter);

        Date expectedDate = new Date();
        doReturn(expectedDate).when(spyAdapter).deserializeToDate(jsonReader);

        Date result = spyAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(spyAdapter).deserializeToDate(jsonReader);
        assertEquals(expectedDate, result);
    }
}
